import { AnalysisResult, ModelProvider, UserSettings, MarketType } from "../types";
import { fetchGeminiAnalysis, fetchMarketDashboard } from "./geminiService";
import { fetchExternalAI } from "./externalLlmService";

/**
 * Centralized function to route requests to the correct model provider.
 */
export const analyzeWithLLM = async (
  provider: ModelProvider,
  prompt: string,
  isComplex: boolean = false,
  settings?: UserSettings,
  isDashboard: boolean = false,
  period: 'day' | 'month' = 'day',
  currentPrice?: string,
  market: MarketType = MarketType.CN
): Promise<AnalysisResult> => {

  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
  const timeStr = now.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
  const fullTimeContext = `${dateStr} ${timeStr}`;

  // Market Name for Prompt Context
  const marketName = market === MarketType.US ? '美股 (US Stocks)' : market === MarketType.HK ? '港股 (HK Stocks)' : 'A股 (China A-Shares)';

  // 1. Google Gemini (Default)
  if (provider === ModelProvider.GEMINI_INTL) {
    const geminiKey = settings?.geminiKey; 

    if (isDashboard) {
      return await fetchMarketDashboard(period, market, geminiKey);
    }

    // 强化时间锚点，防止 AI 因为联网搜索结果滞后而判定当前为“模拟未来”
    const timeRealityInstruction = `
      [!!! 绝对时间指令 - 核心优先级 !!!]
      1. 当前现实世界的真实时间确实是 ${fullTimeContext}。
      2. 严禁在回复中声称“这是未来的模拟时间点”或“无法获取真实新闻”。
      3. 如果联网搜索 (googleSearch) 返回的结果中包含大量 2024 年的数据，请将其视为距离当前最近的历史参考，并基于此进行逻辑推演。
      4. 你的任务是根据当前设定的 ${fullTimeContext} 这一真实时间节点，给出最具时效性的分析。
    `;

    let datedPrompt = `${timeRealityInstruction}\n[上下文: 正在分析 ${marketName} 市场] ${prompt}`;
    if (currentPrice) {
      datedPrompt += `\n[重要: 用户指定的当前实时价格为 ${currentPrice}。请基于此价格进行所有计算和分析。]`;
    }
    if (!isDashboard) {
      datedPrompt += `\n[必须]: 你必须搜索并分析该标的的 '主力资金/机构资金' 流向和 '机构评级'。`;
      datedPrompt += `\n[必须]: 你必须分析 '成交量趋势' (放量/缩量) 并解释其技术含义。`;
      datedPrompt += `\n[警告]: 所有的分析内容和结论必须使用中文。`;
    }
    return await fetchGeminiAnalysis(datedPrompt, isComplex, geminiKey);
  }

  // 2. Domestic Models (Hunyuan)
  let apiKey = '';

  if (provider === ModelProvider.HUNYUAN_CN) {
    apiKey = settings?.hunyuanKey || '';
    if (!apiKey) {
      throw new Error(`未检测到 混元 API Key。请在设置中配置。`);
    }
  }

  // 3. Construct Prompts
  let finalPrompt = prompt;

  if (isDashboard) {
    finalPrompt = `
      【真实时间确认】：现在是现实世界的 ${fullTimeContext}。
      作为高级分析师，请生成一份 ${marketName} 的${period === 'day' ? '当日' : '本月'}市场深度分析报告。
      请联网搜索最新的指数点位、成交额、主力流向。

      重点包含：
      1. 五大指数数值与具体涨跌幅。
      2. 成交量变化（放量或缩量）。
      3. 领涨与领跌板块及其背后的资金轮动逻辑。
      4. 宏观政策导向与外部环境影响。

      请确保数据真实准确。
    `;
  } else {
    // 强化混元的回复逻辑，防止出现 XXX 占位符
    const placeholderPrevention = `
      [!!! 严禁占位符指令 !!!]
      1. 严禁在输出中使用 "XXX"、"xxxx"、"XX%" 或任何未填充的模板占位符。
      2. 如果你无法获取到最新的实时股价数据，请明确说明基于哪一天的历史数据，或者基于用户提供的参考价 ${currentPrice || '（未提供）'} 进行估算。
      3. 所有的量化指标（如均线、乖离率）必须给出具体的数值估算，不得留空。
    `;

    finalPrompt = `${placeholderPrevention}\n[确认真实时间: ${fullTimeContext}] [上下文: 正在分析 ${marketName} 市场] ${prompt}`;
    if (currentPrice) {
       finalPrompt += `\n[用户输入] 当前实时价为: ${currentPrice}。必须基于此价格进行后续所有技术分析（如乖离率计算）。`;
    }
    finalPrompt += `\n[强制要求] 分析 '主力成本' 和 '机构资金流向'。分析 '成交量趋势'。`;
    finalPrompt += `\n[语言要求] 所有输出必须为中文。`;
  }

  // Pass forceJson = true for Dashboard mode for Hunyuan
  return await fetchExternalAI(provider, apiKey, finalPrompt, isDashboard, period, market, isDashboard);
};

import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams } from 'react-router-dom';
import { ModelProvider, AnalysisResult, UserSettings, MarketType } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { fetchStockDetailWithImage } from '../services/geminiService'; // New Service
import { Search, Loader2, ArrowRightCircle, Target, ShieldAlert, Settings, FileText, ChevronRight, BarChart2, Activity, DollarSign, Camera, X, Image as ImageIcon, Layers, AlertCircle, TrendingUp, Compass, ShieldCheck, Zap, Info, ArrowUpCircle, ArrowDownCircle } from 'lucide-react';
import { MARKET_OPTIONS } from '../constants';

interface StockAnalysisProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
  // Props for state persistence (Single Stock)
  savedResult: AnalysisResult | null;
  onResultUpdate: (result: AnalysisResult | null) => void;
  savedQuery: string;
  onQueryUpdate: (query: string) => void;
}

export const StockAnalysis: React.FC<StockAnalysisProps> = ({ 
  currentModel, 
  currentMarket,
  settings, 
  onOpenSettings,
  savedResult,
  onResultUpdate,
  savedQuery,
  onQueryUpdate
}) => {
  const [searchParams] = useSearchParams();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentPrice, setCurrentPrice] = useState('');

  // Image Upload State
  const [selectedImage, setSelectedImage] = useState<string | null>(null); // base64 string
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Extract analysis logic for reuse
  const performAnalysis = async (query: string) => {
    if (!query.trim()) return;

    setLoading(true);
    onResultUpdate(null);
    setError(null);

    const marketLabel = MARKET_OPTIONS.find(m => m.value === currentMarket)?.label || currentMarket;

    try {
      let data: AnalysisResult;

      if (selectedImage && currentModel === ModelProvider.GEMINI_INTL) {
         // --- Multimodal Analysis (Image + Text) ---
         if (!settings.geminiKey) {
            throw new Error("图片分析需要 Gemini API Key，请先在设置中配置。");
         }
         data = await fetchStockDetailWithImage(selectedImage, query, currentMarket, settings.geminiKey, currentPrice);
      } else {
         // --- Text Only Analysis ---
         const prompt = `
            请对 ${marketLabel} 的股票 "${query}" 进行深度量化分析。
            特别包含以下深度量化过滤逻辑：
            1. **基础数据与量化指标 (BIAS/均线)**: 请列出最新的 20/60 日均线和乖离率。
            2. **关键价位 (支撑、压力、止盈、止损)**: 给出具体支撑和压力数值。
            3. **行业 Beta 过滤**: 分析该股与所属板块的同步性。
            4. **量价配合**: 识别是“缩量洗盘”还是“放量派发”。

            输出必须包含以下章节（请务必使用 Markdown 标题）:
            1. 基础数据与量化指标 (BIAS/均线)
            2. 关键价位 (支撑、压力、止盈、止损)
            3. 板块 Beta 与洗盘诊断
            4. 量化评级与操作指令
            5. 核心逻辑
         `;
         data = await analyzeWithLLM(currentModel, prompt, false, settings, false, 'day', currentPrice, currentMarket);
      }

      onResultUpdate(data);
    } catch (err: any) {
      setError(err.message || "分析失败，请检查网络或更换模型");
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    performAnalysis(savedQuery);
  };

  // Handle Image Selection
  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = (reader.result as string).split(',')[1];
        setSelectedImage(base64);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  // Auto-trigger analysis if 'q' param exists and is new
  useEffect(() => {
    const q = searchParams.get('q');
    if (q && q !== savedQuery) {
      onQueryUpdate(q);
      performAnalysis(q);
    }
  }, [searchParams]);

  const extractMetrics = (text: string) => {
    const lines = text.split('\n');
    const metrics: { label: string; value: string }[] = [];
    const others: string[] = [];

    lines.forEach(line => {
      const trimmed = line.trim().replace(/^[-*]\s*/, ''); 
      // Match "Label: Value" patterns
      const match = trimmed.match(/^(\*\*.*?\*\*|[^：:]+?)[:：]\s*(.+)$/);

      if (match && trimmed.length < 100) { 
         const rawLabel = match[1].replace(/\*\*/g, '');
         const rawValue = match[2].replace(/\*\*/g, '');
         metrics.push({ label: rawLabel, value: rawValue });
      } else {
         if (trimmed) others.push(line);
      }
    });
    return { metrics, others };
  };

  const formatText = (text: string) => {
    let formatted = text.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900 font-bold">$1</strong>');

    const redKeywords = /(卖出|止损|跌破|风险|高位|放量滞涨|压力|清仓|追涨|正乖离过大|离场|危险|泡沫)/g;
    const greenKeywords = /(买入|止盈|支撑|反弹|底背离|缩量回调|启动|加仓|洗盘|Alpha走强|低吸|机遇|安全)/g; 

    formatted = formatted.replace(redKeywords, '<span class="text-rose-600 font-bold bg-rose-50 px-1 rounded">$1</span>'); 
    formatted = formatted.replace(greenKeywords, '<span class="text-emerald-600 font-bold bg-emerald-50 px-1 rounded">$1</span>'); 

    return formatted;
  };

  const renderSectionContent = (title: string, body: string) => {
    if (title.includes("基础数据") || title.includes("指标") || title.includes("1.")) {
       const { metrics, others } = extractMetrics(body);
       return (
         <div className="space-y-6">
            {metrics.length > 0 && (
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 {metrics.map((m, i) => (
                   <div key={i} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow group">
                      <div className="text-[10px] font-black text-slate-400 mb-1 uppercase tracking-widest group-hover:text-indigo-500 transition-colors">{m.label}</div>
                      <div className={`text-lg font-black tracking-tight ${m.value.includes('X') || m.value.includes('x') ? 'text-slate-300 animate-pulse' : 'text-slate-800'}`}>
                        {m.value}
                      </div>
                   </div>
                 ))}
              </div>
            )}
            <div className="space-y-2 border-t border-slate-50 pt-4">
               {others.map((line, i) => (
                  <div key={i} className="flex gap-3 items-start">
                     <div className="mt-2 w-1.5 h-1.5 bg-indigo-400 rounded-full shrink-0"></div>
                     <p className="text-sm text-slate-600 font-medium leading-relaxed" dangerouslySetInnerHTML={{__html: formatText(line.replace(/^[-*]\s*/, ''))}}></p>
                  </div>
               ))}
            </div>
         </div>
       );
    }

    if (title.includes("Beta") || title.includes("洗盘") || title.includes("诊断") || title.includes("3.")) {
       return (
         <div className="bg-indigo-50/50 p-6 rounded-[2rem] border border-indigo-100 space-y-4">
            {body.split('\n').filter(l => l.trim()).map((line, i) => (
               <div key={i} className="flex gap-4 items-start">
                  <Compass className="w-5 h-5 text-indigo-500 mt-1 shrink-0" />
                  <p className="text-sm text-slate-700 font-bold leading-relaxed" dangerouslySetInnerHTML={{__html: formatText(line.replace(/^[-*]\s*/, ''))}}></p>
               </div>
            ))}
         </div>
       );
    }

    if (title.includes("关键价位") || title.includes("2.")) {
       return (
         <div className="space-y-3">
            {body.split('\n').filter(l => l.trim()).map((line, i) => {
               const cleanLine = line.replace(/^[-*]\s*/, '');
               let Icon = Info;
               let styleClass = "border-slate-200 bg-slate-50 text-slate-700";

               if (cleanLine.includes("支撑")) { 
                 styleClass = "border-rose-100 bg-rose-50 text-rose-900"; 
                 Icon = ArrowUpCircle; 
               } else if (cleanLine.includes("压力") || cleanLine.includes("阻力")) { 
                 styleClass = "border-emerald-100 bg-emerald-50 text-emerald-900"; 
                 Icon = ArrowDownCircle; 
               } else if (cleanLine.includes("止盈") || cleanLine.includes("止损")) {
                 styleClass = "border-indigo-100 bg-indigo-50 text-indigo-900";
                 Icon = Target;
               }

               return (
                  <div key={i} className={`p-4 rounded-2xl border flex items-center gap-4 transition-all hover:scale-[1.01] ${styleClass}`}>
                     <div className={`p-2 rounded-lg bg-white/60 shadow-sm`}>
                        <Icon className="w-5 h-5" />
                     </div>
                     <p className="text-base font-black tracking-tight" dangerouslySetInnerHTML={{__html: formatText(cleanLine)}}></p>
                  </div>
               );
            })}
         </div>
       )
    }

    return (
       <div className="space-y-3">
          {body.split('\n').filter(l => l.trim()).map((line, i) => (
             <div key={i} className={`flex gap-3 items-start ${line.startsWith('###') ? 'mt-6 mb-2' : ''}`}>
                {!line.startsWith('###') && <div className="mt-2.5 w-1.5 h-1.5 bg-slate-300 rounded-full shrink-0"></div>}
                <p className={`${line.startsWith('###') ? 'text-lg font-black text-slate-800' : 'text-sm text-slate-600 font-medium leading-relaxed'}`} dangerouslySetInnerHTML={{__html: formatText(line.replace(/^#+\s*/, '').replace(/^[-*]\s*/, ''))}}></p>
             </div>
          ))}
       </div>
    );
  };

  const renderAnalysisContent = (content: string) => {
    const sections = content.split(/^#+\s+/gm).filter(Boolean);
    if (sections.length <= 1) {
       return <div className="p-10 text-slate-700 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: formatText(content.replace(/\n/g, '<br/>')) }} />;
    }

    return (
      <div className="grid grid-cols-1 gap-8">
        {sections.map((sec, index) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();

          let Icon = FileText;
          let colorClass = "text-slate-800";
          let bgClass = "bg-slate-50";
          let borderClass = "border-slate-200";

          if (title.includes("基础数据") || title.includes("1.")) { Icon = Activity; colorClass = "text-blue-700"; bgClass = "bg-blue-50/50"; borderClass = "border-blue-100"; }
          else if (title.includes("关键价位") || title.includes("2.")) { Icon = Target; colorClass = "text-amber-700"; bgClass = "bg-amber-50/50"; borderClass = "border-amber-100"; }
          else if (title.includes("Beta") || title.includes("洗盘") || title.includes("3.")) { Icon = Compass; colorClass = "text-indigo-700"; bgClass = "bg-indigo-50/50"; borderClass = "border-indigo-100"; }
          else if (title.includes("指令") || title.includes("操作") || title.includes("4.")) { Icon = Zap; colorClass = "text-emerald-700"; bgClass = "bg-emerald-50/50"; borderClass = "border-emerald-100"; }
          else if (title.includes("逻辑") || title.includes("5.")) { Icon = ShieldCheck; colorClass = "text-slate-900"; bgClass = "bg-slate-100"; borderClass = "border-slate-300"; }

          return (
            <div key={index} className={`rounded-[2.5rem] border ${borderClass} shadow-sm overflow-hidden bg-white hover:shadow-xl transition-all`}>
              <div className={`px-8 py-5 border-b ${borderClass} ${bgClass} flex items-center gap-3`}>
                <div className={`p-2 rounded-xl bg-white shadow-sm`}>
                  <Icon className={`w-6 h-6 ${colorClass}`} />
                </div>
                <h3 className={`font-black text-xl tracking-tight ${colorClass}`}>{title}</h3>
              </div>
              <div className="p-8">
                 {renderSectionContent(title, body)}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-5xl mx-auto">
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 p-8 md:p-12 relative overflow-hidden">
        <div className="absolute right-0 top-0 w-1/4 h-full bg-gradient-to-l from-blue-50 to-transparent pointer-events-none"></div>
        <h2 className="text-3xl font-black text-slate-800 mb-8 flex items-center gap-4 relative z-10">
            <div className="p-3 bg-blue-600 rounded-2xl text-white shadow-xl shadow-blue-100">
              <TrendingUp className="w-8 h-8"/>
            </div>
            个股多维量化诊断
        </h2>

        <form onSubmit={handleSearch} className="max-w-3xl mx-auto space-y-6 relative z-10">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <input
                type="text"
                value={savedQuery}
                onChange={(e) => onQueryUpdate(e.target.value)}
                placeholder={`代码/名称 (如: 000001 平安银行)...`}
                className="w-full h-16 pl-14 pr-6 bg-slate-50 border border-slate-200 rounded-[1.5rem] focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all text-xl font-black text-slate-800"
              />
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 w-6 h-6" />
            </div>

            <div className="relative w-full md:w-40">
              <input
                type="number"
                step="0.01"
                value={currentPrice}
                onChange={(e) => setCurrentPrice(e.target.value)}
                placeholder="参考价"
                className="w-full h-16 pl-12 pr-4 bg-slate-50 border border-slate-200 rounded-[1.5rem] focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all text-lg font-black text-slate-800"
              />
              <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
            </div>

            <div className="flex gap-2 shrink-0">
               <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageSelect} />
               <button 
                 type="button" 
                 onClick={() => fileInputRef.current?.click()} 
                 className={`h-16 w-16 flex items-center justify-center rounded-[1.5rem] border transition-all ${selectedImage ? 'text-indigo-600 bg-indigo-50 border-indigo-200 shadow-inner' : 'text-slate-400 border-slate-200 hover:bg-slate-50'}`}
                 title="上传K线图识别价格与形态"
               >
                 <Camera className="w-8 h-8" />
               </button>
            </div>
          </div>

          {selectedImage && (
             <div className="flex items-center gap-4 p-4 bg-indigo-50 border border-indigo-100 rounded-2xl animate-fade-in">
                <div className="relative w-16 h-16 shrink-0 rounded-xl overflow-hidden border-2 border-indigo-200 shadow-sm">
                   <img src={`data:image/jpeg;base64,${selectedImage}`} className="w-full h-full object-cover" />
                   <button type="button" onClick={clearImage} className="absolute top-0 right-0 p-1 bg-red-500 text-white rounded-bl-lg shadow-sm"><X className="w-3 h-3" /></button>
                </div>
                <div>
                  <div className="text-sm font-black text-indigo-700 flex items-center gap-2 mb-1">
                    <ShieldCheck className="w-4 h-4" /> 视觉对齐引擎已激活
                  </div>
                  <div className="text-[11px] text-indigo-600 font-bold opacity-80 uppercase tracking-wider">AI 将深度识别截图中的量价关系，强制修正搜索数据延迟。</div>
                </div>
             </div>
          )}

          <button 
            type="submit" 
            disabled={loading || !savedQuery} 
            className="w-full h-16 bg-slate-900 hover:bg-slate-800 text-white rounded-[1.5rem] font-black text-xl shadow-2xl hover:shadow-blue-200 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
          >
            {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6" />}
            {loading ? 'AI 量化大脑高能研判中...' : '启动多维深度研判'}
          </button>
        </form>
      </div>

      {savedResult && (
        <div className="animate-slide-up space-y-8 pb-20">
          <div className="flex justify-between items-center px-8">
             <div className="flex items-center gap-3">
               <h3 className="text-2xl font-black text-slate-900">{savedQuery} 诊断报告</h3>
               <span className="text-[10px] px-3 py-1 bg-slate-100 border border-slate-200 rounded-full font-black text-slate-500 uppercase tracking-widest">v{savedResult.modelUsed} Engine</span>
             </div>
             <div className="flex items-center gap-2 px-4 py-1.5 bg-amber-50 text-amber-700 text-xs font-black rounded-full border border-amber-100 shadow-sm">
                <AlertCircle className="w-3.5 h-3.5" /> 深度集成行业 Beta 与视觉形态审计
             </div>
          </div>

          {renderAnalysisContent(savedResult.content)}

          <div className="text-center pt-8">
            <div className="inline-flex items-center gap-3 px-6 py-3 bg-slate-100 rounded-full text-[10px] text-slate-400 font-black uppercase tracking-[0.3em]">
              <Info className="w-4 h-4" /> 分析结果基于量化模型推演，不构成任何投资建议
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { AnalysisResult, ModelProvider, UserSettings, MarketType } from "../types";
import { fetchGeminiAnalysis, fetchMarketDashboard } from "./geminiService";
import { fetchExternalAI } from "./externalLlmService";

/**
 * Centralized function to route requests to the correct model provider.
 */
export const analyzeWithLLM = async (
  provider: ModelProvider,
  prompt: string,
  isComplex: boolean = false,
  settings?: UserSettings,
  isDashboard: boolean = false,
  period: 'day' | 'month' = 'day',
  currentPrice?: string,
  market: MarketType = MarketType.CN
): Promise<AnalysisResult> => {

  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
  const timeStr = now.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
  const fullTimeContext = `${dateStr} ${timeStr}`;

  const marketName = market === MarketType.US ? '美股' : market === MarketType.HK ? '港股' : 'A股';

  if (provider === ModelProvider.GEMINI_INTL) {
    const geminiKey = settings?.geminiKey; 

    if (isDashboard) {
      return await fetchMarketDashboard(period, market, geminiKey);
    }

    const timeRealityInstruction = `
      [!!! 绝对时间指令 !!!]
      1. 当前真实时间: ${fullTimeContext}。
      2. 严禁声称“无法获取实时数据”。
      3. 基于 ${fullTimeContext} 进行逻辑推演。
    `;

    let datedPrompt = `${timeRealityInstruction}\n[分析对象: ${marketName}] ${prompt}`;
    if (currentPrice) {
      datedPrompt += `\n[参考价: ${currentPrice}]`;
    }
    return await fetchGeminiAnalysis(datedPrompt, isComplex, geminiKey);
  }

  // --- Hunyuan Optimization ---
  if (provider === ModelProvider.HUNYUAN_CN) {
    const apiKey = settings?.hunyuanKey || '';
    if (!apiKey) throw new Error(`未检测到 混元 API Key。`);

    let finalPrompt = "";

    if (isDashboard) {
      finalPrompt = `[时间: ${fullTimeContext}] 生成 ${marketName} ${period === 'day' ? '当日' : '本月'}市场快报。包含指数、成交额、主力流向。JSON格式。`;
    } else {
      // 极简高效指令，减少模型推理时的冗余思考，提升生成速度
      finalPrompt = `
        [时间锚点: ${fullTimeContext}] [市场: ${marketName}]
        任务：对 ${prompt} 进行核心量化研判。
        要求：
        1. 严禁使用 "XXX" 等占位符，无数据则基于参考价 ${currentPrice || '用户未提供'} 估算。
        2. 结构清晰，包含：指标分析、关键价位(支撑/压力)、操作指令。
        3. 回复务必精炼，避免废话，直接给干货，提升响应速度。
      `;
    }

    // 针对个股分析，降低 max_tokens 到 2000 以缩短 TTFB 和生成时间
    return await fetchExternalAI(provider, apiKey, finalPrompt, isDashboard, period, market, isDashboard, isDashboard ? 4000 : 2000);
  }

  throw new Error("Unsupported provider");
};

