/**
 * Enhanced fetch with streaming support
 */
export const fetchExternalAIStream = async (
  provider: ModelProvider,
  apiKey: string,
  prompt: string,
  onChunk: (text: string) => void,
  maxTokens: number = 2000
): Promise<void> => {
  const config = PROVIDER_CONFIG[provider as keyof typeof PROVIDER_CONFIG];
  if (!config) throw new Error(`Model provider configuration missing.`);

  const response = await fetch(`${config.baseUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`
    },
    body: JSON.stringify({
      model: config.model,
      messages: [
        { role: 'system', content: "You are a senior stock analyst. Output concise Markdown. NO placeholders like XXX." },
        { role: 'user', content: prompt }
      ],
      temperature: 0.1,
      max_tokens: maxTokens,
      stream: true
    })
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`API Error: ${response.status} - ${errorText}`);
  }

  const reader = response.body?.getReader();
  const decoder = new TextDecoder();
  let finished = false;

  if (!reader) throw new Error("Failed to initialize stream reader.");

  while (!finished) {
    const { value, done } = await reader.read();
    if (done) {
      finished = true;
      break;
    }
    const chunk = decoder.decode(value, { stream: true });
    const lines = chunk.split('\n');

    for (const line of lines) {
      if (line.trim().startsWith('data: ')) {
        const jsonStr = line.replace('data: ', '').trim();
        if (jsonStr === '[DONE]') {
          finished = true;
          break;
        }
        try {
          const data = JSON.parse(jsonStr);
          const content = data.choices[0]?.delta?.content || "";
          if (content) onChunk(content);
        } catch (e) {
          // Skip malformed chunks
        }
      }
    }
  }
};

