  }

  const reader = response.body?.getReader();
  const decoder = new TextDecoder();
  let finished = false;

  if (!reader) throw new Error("Failed to initialize stream reader.");

  while (!finished) {
    const { value, done } = await reader.read();
    if (done) {
      finished = true;
      break;
    }
